import{_ as d}from"./chunks/demo-doc.NIuiqrK9.js";import{c as r,Q as t,j as o,m as i}from"./chunks/framework.ByJJFMw8.js";const f=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/overview.md","filePath":"guide/overview.md","lastUpdated":1782194586000}'),c={name:"guide/overview.md"};function a(l,e,s,n,h,D){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>Flyfish Viewer 可以为业务系统快速补齐文件在线预览能力。它不同于依赖后端转码的方案，核心解析和渲染都在浏览器端完成，不会额外占用服务器执行 Office 转 PDF、临时文件清理或异步转换任务。</p><p>这让它特别适合静态部署、内网私有化、低运维成本和多系统复用场景。查看<a href="/guide/quickstart">快速开始</a>可以直接跑通第一个预览示例。</p><h2 id="当前能力" tabindex="-1">当前能力 <a class="header-anchor" href="#当前能力" aria-label="Permalink to &quot;当前能力&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>多格式预览</h3><p>内置 206 个扩展名映射和 24 条预览链路，覆盖 Word、Excel、PowerPoint、PDF、OFD、Typst、XMind 脑图、压缩包、邮件、OLB/DRA/GDS/OASIS、CAD、地理数据、3D 模型、Excalidraw、draw.io、Mermaid、PlantUML、EPUB、UMD、Markdown、图片、音视频、字体、PSD 图层资产、结构化数据以及代码/Git patch/bundle。</p></div><div class="doc-card"><h3>纯前端渲染</h3><p>大部分格式不需要后端转码服务。业务侧只需要提供可访问 URL、File 或二进制数据包装后的 File。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>PDF、OFD、Typst、XMind、压缩包、邮件、OLB/DRA/GDS/OASIS、CAD、地理数据、3D 模型、绘图、Office、EPUB、UMD、Markdown、HLS、HEIC、字体/数据资产和代码高亮都按需进入对应预览链路，减少无关格式的加载成本。</p></div><div class="doc-card"><h3>多接入路线</h3><p>Vanilla JS / Pure Web、Vue3、Vue2.7、Vue2.6、React 18/19、React 16.8/17、jQuery 和 Svelte 都有对应 npm 包；标准组件包复用同一套 core 能力，并提供各自生态的组件体验。</p></div></div><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>交付边界清楚。</strong> 组件、Demo、文档站、开源总仓库、npm tarball 和构建脚本都围绕开源分发维护，接入方可以先验收效果再决定集成方式。</li><li><strong>视觉体验更接近真实阅读。</strong> Word 文档使用灰色页面底和白色纸张；PDF 提供缩放、页码、导航窗格和可视宽度自适应，避免打开后内容被挤压或不可读。</li><li><strong>格式策略务实。</strong> PPTX 已切换到独立开源的 <code>@file-viewer/pptx</code> 原生引擎，重点增强组合图形、主题背景、图片裁剪和 EMF 矢量图片；OFD 通过 <code>@file-viewer/renderer-ofd</code> 基于 <code>DLTech21/ofd.js</code> 源码链路预览；Typst 直接读取 <code>.typ</code> / <code>.typst</code> 源文件，命中格式时才加载浏览器 WASM 编译与 SVG 渲染链路；XMind 使用 <code>@file-viewer/renderer-mindmap</code> + <code>@ljheee/xmind-parser</code> 解析 XMind 8 / 2020+ 文件包并离线渲染多 sheet 脑图，画布交互由 <code>@panzoom/panzoom</code> 提供拖拽平移、移动端双指缩放和适配画布；压缩包用 <code>libarchive.js</code> Worker 按需解压内部文件；邮件用 <code>postal-mime</code> / <code>@kenjiuno/msgreader</code> 解析正文和附件，并兼容 MBOX 归档；EDA 由 <code>@file-viewer/renderer-eda</code> 独立承接，OLB/DRA 做结构树、对象候选、属性、可读字符串和诊断预览，GDSII 读取标准记录并生成 SVG / WebGL 版图预览，OASIS 文本夹具可生成 SVG，真实二进制 OASIS 先做安全结构索引；CAD 使用 <code>@flyfish-dev/cad-viewer</code> 支持 DWG / DXF / DWF / DWFx / XPS，DWG 通过 Worker + LibreDWG WASM 按需解析，DWF/DWFx/XPS 通过 native <code>dwf-viewer</code> 渲染 W2D/W3D/XPS 图形；地理数据通过独立 <code>@file-viewer/renderer-geo</code> 标准化 GeoJSON/KML/GPX/SHP 并做离线 SVG 预览；3D 模型通过 <code>@file-viewer/renderer-3d</code> + Three.js loaders 支持常见浏览器可渲染格式，STEP/IGES/IFC/3DM/BREP 由 <code>@file-viewer/geometry-engine</code> 维护轻量签名识别和 OpenCascade / web-ifc / rhino3dm 独立内核路线；Excalidraw 使用官方导出 SVG，draw.io 默认使用随 viewer assets 分发的官方 diagrams.net 离线 viewer 并在异常时回退内置 SVG；EPUB 使用 <code>epubjs</code>；UMD 电子书按文件结构解析元数据、目录和 zlib 正文段；音视频使用原生媒体能力并按需补 HLS/MIDI 解析；代码/日志由 <code>@file-viewer/renderer-text</code> 使用 <code>highlight.js</code> 轻量高亮，HTML 按源码展示；字体、PSD、SQLite、WASM、Parquet、Avro 和 WebArchive 由独立 <code>@file-viewer/renderer-data</code> 做安全摘要或结构预览。内置 CAD、3D、绘图、脑图、压缩包、邮件、EDA、Typst、UMD、音视频、地理数据和结构化数据回归样例来源清楚，方便复现实文件兼容问题。</li><li><strong>适合平台复用。</strong> 多个系统可以共用同一套 core 能力和 组件语义，只要升级对应 npm 包即可统一更新预览能力。</li><li><strong>全生态同步维护。</strong> Vanilla JS / Pure Web 使用 <code>@file-viewer/web</code>，Vue3 使用 <code>@file-viewer/vue3</code>，Vue2.7 使用 <code>@file-viewer/vue2.7</code>，Vue2.6 使用 <code>@file-viewer/vue2.6</code>，React 18/19 使用 <code>@file-viewer/react</code>，React 16.8/17 使用 <code>@file-viewer/react-legacy</code>，jQuery 使用 <code>@file-viewer/jquery</code>，Svelte 使用 <code>@file-viewer/svelte</code>。历史 <code>@flyfish-group/*</code> 包继续同步维护，但新项目优先选择标准包名。</li><li><strong>二开路径明确。</strong> 开源总仓库提供 core、标准组件包、Demo、文档和 release 下载物；飞鱼小铺作为打赏和优先技术支持入口，避免把源码分发和服务支持混在一起。</li></ul><h2 id="关键特性" tabindex="-1">关键特性 <a class="header-anchor" href="#关键特性" aria-label="Permalink to &quot;关键特性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>Word</td><td><code>@file-viewer/renderer-word</code> 承接 DOCX/DOC/RTF/ODT；<code>docx</code> 使用自研 <code>@file-viewer/docx</code>，支持 Worker 解析、连续流式阅读、目录字段缓存和异步分批渲染；<code>.doc</code> 使用 <code>msdoc-viewer</code>，保留文档页面感</td></tr><tr><td>Excel</td><td>多种表格格式统一进入表格预览链路，保留常见尺寸、合并和样式</td></tr><tr><td>PowerPoint</td><td><code>@file-viewer/pptx</code> 原生引擎，增强组合图形坐标、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图预览</td></tr><tr><td>PDF</td><td>基于 <code>pdfjs-dist</code>，同源 URL 默认渐进读取，服务端支持 Range 时自动分片加载，支持缩放工具栏、页码状态、导航窗格、宽度适配、完整打印和导出 HTML</td></tr><tr><td>操作栏</td><td>支持下载原文件、打印完整渲染结果、导出渲染后 HTML、统一缩放，以及文字或图片水印；打印和缩放按钮会按当前格式和渲染链路动态显隐</td></tr><tr><td>OFD</td><td>使用 <code>@file-viewer/renderer-ofd</code> + <code>DLTech21/ofd.js</code> 源码链路，重型能力按需加载</td></tr><tr><td>Typst</td><td>直接读取 <code>.typ</code> / <code>.typst</code> 源文件，按需加载浏览器 WASM 编译与 SVG 渲染链路，支持按页预览、打印和 HTML 导出</td></tr><tr><td>压缩包</td><td>使用 <code>libarchive.js</code> Worker 读取目录，内部文件按需解压、缓存并继续在线预览</td></tr><tr><td>邮件</td><td>EML / MSG / MBOX 支持头信息、HTML/文本正文、附件下载和附件继续预览</td></tr><tr><td>EDA</td><td><code>@file-viewer/renderer-eda</code> 承接 OLB / DRA / GDSII / OASIS；GDSII 可生成 SVG / WebGL 快速版图，OASIS 文本夹具可生成 SVG，真实二进制 OASIS / Cadence 高保真几何保留独立 WASM 内核路线</td></tr><tr><td>CAD</td><td>使用 <code>@flyfish-dev/cad-viewer</code>，支持 DWG / DXF / DWF / DWFx / XPS 预览；DWG 通过 Worker + LibreDWG WASM 按需解析，DWF/DWFx/XPS 通过 native renderer 渲染</td></tr><tr><td>地理数据</td><td>GeoJSON / KML / GPX / SHP 转为统一 GeoJSON 后离线 SVG 预览，适合轨迹、边界和点位附件</td></tr><tr><td>3D 模型</td><td>使用 <code>@file-viewer/renderer-3d</code> + Three.js loaders 交互渲染 GLTF/GLB、OBJ、STL、PLY、FBX、DAE、3DS、3MF、AMF、USD/USDZ、KMZ、点云和 VTK 等格式</td></tr><tr><td>绘图</td><td>Excalidraw 使用官方 <code>restore</code> + <code>exportToSvg</code>，draw.io 默认使用官方 diagrams.net 离线 <code>GraphViewer</code>，Mermaid 使用官方 SVG 渲染，PlantUML 默认离线源码预览并支持自托管 SVG 服务，绘图画布支持拖动和统一缩放</td></tr><tr><td>电子书</td><td>EPUB 使用 <code>epubjs</code>，UMD 解析移动电子书封装、目录和压缩正文</td></tr><tr><td>代码/文本</td><td><code>@file-viewer/renderer-text</code> 使用 <code>highlight.js</code> 高亮多语言源码、日志、配置、Notebook、HTTP、Graphviz、Proto、HCL、TeX 和 diff；patch 提供左右比对，git bundle 展示 refs、历史、树和文件</td></tr><tr><td>图片/音视频</td><td>图片使用浏览器原生能力和轻量查看器，HEIC/HEIF 按需转换，音频、MIDI、MP4、WEBM 和 HLS 按类型选择原生能力或轻量解析器</td></tr><tr><td>字体/设计/数据</td><td><code>@file-viewer/renderer-data</code> 承接字体、PSD、AI/EPS、SQLite、WASM、Parquet、Avro 和 WebArchive；PSD 支持图层显隐、重绘和统一缩放</td></tr></tbody></table><h2 id="开源总仓库与支持" tabindex="-1">开源总仓库与支持 <a class="header-anchor" href="#开源总仓库与支持" aria-label="Permalink to &quot;开源总仓库与支持&quot;">​</a></h2><p>开源总仓库用于分发 core、标准组件包、兼容包、主 Demo、组件 Demo、文档源码、构建产物、示例和 release tarball。私有 Gitea 继续作为完整聚合仓，提供统一发布脚本、内部集成历史和优先技术支持；需要支持项目或获得优先协助的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，请我们喝杯柠檬水。</p><p>项目遵循 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code> 或 <code>@flyfish-group/file-viewer</code>。如果你基于项目修复了通用问题或增强了通用能力，也欢迎一起贡献。</p><div class="doc-shot"><img src="'+d+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">Word 预览在视觉上回到灰色工作台与白色纸张的阅读模型，用户打开正式文档时会更接近熟悉的文档软件体验。</p></div>',13)])])}const p=r(c,[["render",a]]);export{f as __pageData,p as default};
